import{_ as t,o,c as a,a2 as r}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Prompt Engineering for Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/prompt-engineering/index.md","filePath":"research/concepts/prompt-engineering/index.md"}'),n={name:"research/concepts/prompt-engineering/index.md"};function s(i,e,d,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="prompt-engineering-for-coding-agents" tabindex="-1">Prompt Engineering for Coding Agents <a class="header-anchor" href="#prompt-engineering-for-coding-agents" aria-label="Permalink to &quot;Prompt Engineering for Coding Agents&quot;">​</a></h1><blockquote><p>A comprehensive research guide based on analysis of 17 open-source coding agents, examining how they craft prompts to maximize model performance on software engineering tasks.</p></blockquote><h2 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h2><p>Large language models are powerful, but their usefulness in coding agents depends almost entirely on how they are prompted. A well-engineered prompt can mean the difference between an agent that reliably edits files, runs tests, and resolves issues — and one that hallucinates function signatures, produces malformed diffs, or wanders off-task.</p><p>Coding agents face unique prompt engineering challenges that don&#39;t arise in chatbot or content-generation settings:</p><ul><li><strong>Tool orchestration</strong> — Models must decide when and how to call tools (file editors, terminals, search), often dozens of times in a single task.</li><li><strong>Structured output under pressure</strong> — A single misplaced newline in a diff or JSON block can break a file. Prompts must constrain output format without sacrificing the model&#39;s reasoning ability.</li><li><strong>Long-context management</strong> — Codebases are large. Agents must selectively include context while staying within token limits and keeping costs manageable.</li><li><strong>Multi-model support</strong> — Most agents target multiple providers. The same task may need different prompting strategies for Claude, GPT-4, Gemini, and open-weight models.</li><li><strong>Agentic loops</strong> — Unlike single-shot prompts, agents run in loops where each iteration&#39;s prompt depends on prior tool results. Errors compound quickly.</li></ul><p>This research folder distills the patterns, trade-offs, and techniques used by the leading open-source coding agents to solve these problems.</p><hr><h2 id="agents-studied" tabindex="-1">Agents Studied <a class="header-anchor" href="#agents-studied" aria-label="Permalink to &quot;Agents Studied&quot;">​</a></h2><p>This research is based on direct source-code analysis of <strong>17 open-source coding agents</strong>:</p><table tabindex="0"><thead><tr><th>#</th><th>Agent</th><th>Notable For</th></tr></thead><tbody><tr><td>1</td><td><strong>Claude Code</strong></td><td>Anthropic&#39;s reference agent; extensive tool-use prompting</td></tr><tr><td>2</td><td><strong>Aider</strong></td><td>Pioneered diff formats (udiff, whole-file, architect mode)</td></tr><tr><td>3</td><td><strong>Codex</strong></td><td>OpenAI&#39;s CLI agent; sandboxed execution model</td></tr><tr><td>4</td><td><strong>OpenHands</strong></td><td>Research-grade agent with microagent architecture</td></tr><tr><td>5</td><td><strong>ForgeCode</strong></td><td>Lightweight Rust agent with focused prompt design</td></tr><tr><td>6</td><td><strong>Goose</strong></td><td>Block-based extensible agent with provider abstraction</td></tr><tr><td>7</td><td><strong>Gemini CLI</strong></td><td>Google&#39;s agent; optimized for Gemini-family models</td></tr><tr><td>8</td><td><strong>OpenCode</strong></td><td>Terminal-native agent with multi-provider support</td></tr><tr><td>9</td><td><strong>Warp</strong></td><td>Terminal-integrated AI with shell-aware prompting</td></tr><tr><td>10</td><td><strong>Junie CLI</strong></td><td>JetBrains&#39; agent; IDE-context-aware prompts</td></tr><tr><td>11</td><td><strong>Droid</strong></td><td>Android-focused agent with domain-specific tooling</td></tr><tr><td>12</td><td><strong>Sage-Agent</strong></td><td>Minimal agent emphasizing chain-of-thought reasoning</td></tr><tr><td>13</td><td><strong>Mini-SWE-Agent</strong></td><td>Compact research agent for SWE-bench tasks</td></tr><tr><td>14</td><td><strong>TongAgents</strong></td><td>Multi-agent framework with role-specialized prompts</td></tr><tr><td>15</td><td><strong>Ante</strong></td><td>Convention-driven agent with strong structured output</td></tr><tr><td>16</td><td><strong>Capy</strong></td><td>Copy-edit focused agent with careful diff handling</td></tr><tr><td>17</td><td><strong>Pi-Coding-Agent</strong></td><td>Community agent with iterative refinement loops</td></tr></tbody></table><h3 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h3><p>For each agent, we examined:</p><ol><li><strong>System prompt templates</strong> — The static instructions sent at conversation start.</li><li><strong>Tool descriptions</strong> — How each tool&#39;s name, description, and parameter schema are defined.</li><li><strong>Output format directives</strong> — How agents constrain model output (JSON schemas, diff formats, XML tags, markdown fences).</li><li><strong>Few-shot examples</strong> — Whether and how examples are embedded in prompts.</li><li><strong>Reasoning directives</strong> — Chain-of-thought, planning, or reflection instructions.</li><li><strong>Model-specific adaptations</strong> — Conditional prompt logic based on the target model.</li><li><strong>Caching strategies</strong> — How prompts are structured to maximize cache hits.</li></ol><p>All analysis was performed on publicly available source code. Commit references are noted where relevant in individual topic files.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><p>Each file below covers a specific dimension of prompt engineering as practiced by these agents.</p><h3 id="core-techniques" tabindex="-1">Core Techniques <a class="header-anchor" href="#core-techniques" aria-label="Permalink to &quot;Core Techniques&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Topic</th><th>Summary</th></tr></thead><tbody><tr><td><a href="./system-prompts.html">system-prompts.md</a></td><td>System Prompt Design</td><td>How agents structure the system message: identity, rules, capabilities, constraints, and behavioral guardrails. Covers prompt composition patterns (static vs. dynamic sections), persona framing, and how agents inject repository context.</td></tr><tr><td><a href="./tool-descriptions.html">tool-descriptions.md</a></td><td>Tool Description Engineering</td><td>Writing tool names, descriptions, and parameter schemas that models actually follow. Covers the gap between &quot;technically correct&quot; and &quot;behaviorally effective&quot; tool definitions, with examples of descriptions that reduced error rates.</td></tr><tr><td><a href="./few-shot-examples.html">few-shot-examples.md</a></td><td>Few-Shot Examples</td><td>When and how to embed examples in coding prompts. Covers format-demonstration examples (showing desired output shape), error-recovery examples, and the trade-off between example quality and token cost.</td></tr><tr><td><a href="./chain-of-thought.html">chain-of-thought.md</a></td><td>Reasoning Strategies</td><td>How agents elicit step-by-step reasoning: explicit chain-of-thought directives, think-then-act patterns, planning phases, and reflection/retry loops. Includes analysis of which agents use extended thinking features.</td></tr><tr><td><a href="./structured-output.html">structured-output.md</a></td><td>Structured Output</td><td>Getting models to produce valid JSON, code blocks, diffs, and tool calls. Covers XML-tag wrapping, JSON mode, diff format design (search/replace, udiff, whole-file), and validation/retry strategies when output is malformed.</td></tr></tbody></table><h3 id="optimization-adaptation" tabindex="-1">Optimization &amp; Adaptation <a class="header-anchor" href="#optimization-adaptation" aria-label="Permalink to &quot;Optimization &amp; Adaptation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Topic</th><th>Summary</th></tr></thead><tbody><tr><td><a href="./prompt-caching.html">prompt-caching.md</a></td><td>Prompt Caching</td><td>How provider caching mechanisms (Anthropic cache control, OpenAI automatic caching, Gemini context caching) work, and how agents structure prompts to maximize cache hit rates. Includes cost analysis and breakeven calculations.</td></tr><tr><td><a href="./model-specific-tuning.html">model-specific-tuning.md</a></td><td>Model-Specific Tuning</td><td>Adapting prompts per model family. Covers differences in how Claude, GPT-4, Gemini, and open-weight models respond to the same instructions, and how agents conditionally adjust prompts based on the active model.</td></tr></tbody></table><h3 id="comparative-analysis" tabindex="-1">Comparative Analysis <a class="header-anchor" href="#comparative-analysis" aria-label="Permalink to &quot;Comparative Analysis&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Topic</th><th>Summary</th></tr></thead><tbody><tr><td><a href="./agent-comparison.html">agent-comparison.md</a></td><td>Agent Comparison</td><td>Side-by-side analysis of how all 17 agents approach prompt engineering. Feature matrix, architectural patterns, and a taxonomy of design decisions (monolithic vs. composed prompts, static vs. dynamic, etc.).</td></tr><tr><td><a href="./tools-and-projects.html">tools-and-projects.md</a></td><td>Tools &amp; Resources</td><td>Prompt engineering libraries, testing frameworks, and related projects. Covers tools like PromptFoo, LangSmith, and provider playgrounds, plus academic papers relevant to coding-agent prompting.</td></tr></tbody></table><hr><h2 id="key-takeaways-preview" tabindex="-1">Key Takeaways (Preview) <a class="header-anchor" href="#key-takeaways-preview" aria-label="Permalink to &quot;Key Takeaways (Preview)&quot;">​</a></h2><p>These themes emerged repeatedly across the 17 agents studied:</p><h3 id="_1-system-prompts-are-living-documents" tabindex="-1">1. System Prompts Are Living Documents <a class="header-anchor" href="#_1-system-prompts-are-living-documents" aria-label="Permalink to &quot;1. System Prompts Are Living Documents&quot;">​</a></h3><p>No agent ships a single static system prompt. Every agent dynamically composes the system message from multiple sections — identity, tool lists, repository context, user preferences, and behavioral rules — assembled at runtime based on the current state.</p><h3 id="_2-tool-descriptions-are-underrated" tabindex="-1">2. Tool Descriptions Are Underrated <a class="header-anchor" href="#_2-tool-descriptions-are-underrated" aria-label="Permalink to &quot;2. Tool Descriptions Are Underrated&quot;">​</a></h3><p>The quality of tool descriptions has an outsized impact on agent behavior. Several agents (notably Claude Code and Aider) include behavioral guidance <em>inside</em> tool descriptions — not just what the tool does, but when to use it, common mistakes to avoid, and examples of correct invocation.</p><h3 id="_3-diff-format-is-a-pivotal-design-decision" tabindex="-1">3. Diff Format Is a Pivotal Design Decision <a class="header-anchor" href="#_3-diff-format-is-a-pivotal-design-decision" aria-label="Permalink to &quot;3. Diff Format Is a Pivotal Design Decision&quot;">​</a></h3><p>How an agent asks the model to express code changes (whole-file replacement, unified diff, search/replace blocks, line-numbered edits) is one of the most consequential prompt engineering choices. Aider&#39;s research on this is particularly instructive — they tested multiple formats and found significant accuracy differences across models.</p><h3 id="_4-structured-output-requires-defense-in-depth" tabindex="-1">4. Structured Output Requires Defense in Depth <a class="header-anchor" href="#_4-structured-output-requires-defense-in-depth" aria-label="Permalink to &quot;4. Structured Output Requires Defense in Depth&quot;">​</a></h3><p>No single technique reliably produces valid structured output. The most robust agents combine multiple strategies: format instructions in the system prompt, examples showing the exact shape, XML/JSON wrapper tags, regex-based extraction as a fallback, and retry-with-error-feedback loops when parsing fails.</p><h3 id="_5-caching-changes-how-you-write-prompts" tabindex="-1">5. Caching Changes How You Write Prompts <a class="header-anchor" href="#_5-caching-changes-how-you-write-prompts" aria-label="Permalink to &quot;5. Caching Changes How You Write Prompts&quot;">​</a></h3><p>Provider caching mechanisms reward prompts that keep a stable prefix. This creates a tension with dynamic prompt composition — agents must balance personalization against cache efficiency. The best agents solve this by ordering sections from most-stable to least-stable.</p><h3 id="_6-models-are-not-interchangeable" tabindex="-1">6. Models Are Not Interchangeable <a class="header-anchor" href="#_6-models-are-not-interchangeable" aria-label="Permalink to &quot;6. Models Are Not Interchangeable&quot;">​</a></h3><p>The same prompt can produce excellent results with one model and poor results with another. Agents that support multiple providers almost always include model-specific prompt adjustments — different diff formats, different levels of explicitness, different temperature settings, and sometimes entirely different system prompts.</p><h3 id="_7-less-is-often-more" tabindex="-1">7. Less Is Often More <a class="header-anchor" href="#_7-less-is-often-more" aria-label="Permalink to &quot;7. Less Is Often More&quot;">​</a></h3><p>Several agents found that shorter, more focused prompts outperform longer, more detailed ones — especially for capable models. The trick is knowing which instructions the model already &quot;knows&quot; and which it genuinely needs to be told.</p><hr><h2 id="how-to-use-this-research" tabindex="-1">How to Use This Research <a class="header-anchor" href="#how-to-use-this-research" aria-label="Permalink to &quot;How to Use This Research&quot;">​</a></h2><ul><li><strong>Building a coding agent?</strong> Start with <a href="./system-prompts.html">system-prompts.md</a> and <a href="./tool-descriptions.html">tool-descriptions.md</a> for foundational patterns, then read <a href="./structured-output.html">structured-output.md</a> for output format design.</li><li><strong>Optimizing an existing agent?</strong> Check <a href="./prompt-caching.html">prompt-caching.md</a> for cost reduction and <a href="./model-specific-tuning.html">model-specific-tuning.md</a> for per-model improvements.</li><li><strong>Comparing approaches?</strong> The <a href="./agent-comparison.html">agent-comparison.md</a> file provides a feature matrix across all 17 agents.</li><li><strong>Looking for tools?</strong> See <a href="./tools-and-projects.html">tools-and-projects.md</a> for testing frameworks and prompt libraries.</li></ul><hr><h2 id="conventions" tabindex="-1">Conventions <a class="header-anchor" href="#conventions" aria-label="Permalink to &quot;Conventions&quot;">​</a></h2><p>Throughout these files:</p><ul><li><strong>Direct quotes</strong> from agent source code are shown in fenced code blocks with a file path comment indicating the source.</li><li><strong>Agent names</strong> are bolded on first mention in each section.</li><li><strong>Cross-references</strong> between files use relative markdown links.</li><li>Findings are labeled with confidence levels where appropriate: <ul><li>🟢 <strong>Observed in 10+ agents</strong> — Strong consensus pattern</li><li>🟡 <strong>Observed in 4–9 agents</strong> — Common but not universal</li><li>🔴 <strong>Observed in 1–3 agents</strong> — Niche or experimental approach</li></ul></li></ul><hr><p><em>Last updated: July 2025</em><em>Source: Direct analysis of public repositories for all 17 agents listed above.</em></p>',50)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
